import re
def extract_creds(http_list):
    for data in http_list:
        t = data if isinstance(data,str) else data.decode('utf-8',errors='replace')
        if not t.startswith('POST'): continue
        host = re.search(r'Host:\s*([^\r\n]+)',t)
