    level = 'GOOD' if score>80 else 'NEEDS IMPROVEMENT' if score>60 else 'CRITICAL'
    print('=== NETWORK SECURITY SCORECARD ===')
    for d in deductions: print(f'  {d}')
    print(f'  Score: {score}/100 ({level})')
